import React from "react";

export const Gallery = (props) => {
  const d = props.data;
  const items = d && d.items ? d.items : [];
  const title = d && d.title ? d.title : "Portfólio";
  const subtitle = d && d.subtitle ? d.subtitle : "";

  return (
    <div id="portfolio" className="text-center 55lab-portfolio-wrap">
      <div className="container">
        <div className="section-title">
          <h2>{title}</h2>
          {subtitle ? <p>{subtitle}</p> : null}
        </div>
        <div className="row">
          {items.map((project, i) => (
            <div
              key={`${project.title}-${i}`}
              className="col-xs-12 col-sm-6 col-md-3"
            >
              <article className="55lab-portfolio-card">
                <h3>{project.title}</h3>
                <p className="desc">{project.description}</p>
                <span className="tech">{project.tech}</span>
              </article>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};
